// // This module implements a 4-bit register that loads data on the falling edge of the clock and resets asynchronously.
module top_module(
	input clk,
	input reset,
	input load,
	input [3:0] data_in,
	output reg [3:0] data_out);always @(posedge clk or posedge reset) begin
	if (reset)
		data_out <= 4'b0000;
	else if (load)
		data_out <= data_in;
end

endmodule
